import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { tap, catchError } from 'rxjs/operators';
import { CartItem } from '../models/models';
import { AuthService } from './auth.service';

@Injectable({
  providedIn: 'root'
})
export class CartService {
  private apiUrl = 'http://localhost:3000/api/cart';

  constructor(
    private http: HttpClient,
    private authService: AuthService
  ) {}

  getCartItems(): Observable<CartItem[]> {
    console.log('🛒 Fetching cart items...');
    return this.http.get<CartItem[]>(this.apiUrl).pipe(
      tap(items => {
        console.log('📦 Cart items received:', items);
        this.authService.updateCartCount(items.length);
      }),
      catchError(error => {
        console.error('❌ Error fetching cart:', error);
        throw error;
      })
    );
  }

  addToCart(productId: number, quantity: number): Observable<any> {
    console.log('➕ Adding to cart:', { productId, quantity });
    return this.http.post(this.apiUrl, { productId, quantity }).pipe(
      tap(response => {
        console.log('✅ Add to cart response:', response);
        this.getCartCount(); // Refresh cart count
      }),
      catchError(error => {
        console.error('❌ Error adding to cart:', error);
        throw error;
      })
    );
  }

  updateCartItem(itemId: number, quantity: number): Observable<any> {
    return this.http.put(`${this.apiUrl}/${itemId}`, { quantity }).pipe(
      tap(() => this.getCartCount())
    );
  }

  removeFromCart(itemId: number): Observable<any> {
    return this.http.delete(`${this.apiUrl}/${itemId}`).pipe(
      tap(() => this.getCartCount())
    );
  }

  getCartCount(): void {
    this.getCartItems().subscribe({
      next: (items) => {
        this.authService.updateCartCount(items.length);
      },
      error: (error) => {
        console.error('Error fetching cart count:', error);
      }
    });
  }
}
